bookSourceComment:

jm = Object.keys(link_Params).map((key)=>link_Params[key]).join("");
_md5 = String(java.md5Encode(jm));
md5 = _md5.substring(3,_md5.length-5);
api_Params = {
   "ver": "1.6.4",
   "md5": md5
};
body = Object.assign(link_Params, api_Params);
option = {'method':'POST','body':JSON.stringify(body)};
url = link_Urlpath +","+ JSON.stringify(option);

