		title: title,
		url: url,
		style: {
				layout_flexGrow: type1,
				layout_flexBasisPercent: type2
			}
	});

push('榜单', null, 1, 1);
  bd=["综合","新书","完结","男生","女生","收藏"];
    bd.map((title,type)=>{					
			url = `@js:link_Urlpath = "/Book/RankingList";
	   	link_Params =	{"ranking_id":${type+91},"start":(page-1)*20,"limit":20};	
		 	eval(String(source.bookSourceComment));`;

				if(type+1 <= bd.length - bd.length%3)
			 {	push(title, url, 1, 0.25);}
				else{ push(title, url, 0, 0.3);}										
			});

