];
fl.map([title,gender,list]=>{

	push(title, null, 1, 1);
	  list.map((title,type)=>{
	  	url = `@js:link_Urlpath = "/Book/QueryBookForCtgr";
	   	link_Params =	{"type":${type+1+Number(gender)},"category":0,"serials":"不限","vip":"不限","start":(page-1)*20,"limit":20};	
